// Convierte la lista de usuarios en items individuales para iterar
const data = $input.first().json;
const usuarios = data.usuarios || [];

return usuarios.map(u => ({ json: u }));

// Formatea el resumen personalizado para cada usuario
const metricas = $input.first().json;
const usuario = $('Separar por usuario').item.json;
const fondos = metricas.fondos || [];
const periodo = metricas.periodo || '1mo';

const fmtPct = v => v != null ? `${(v * 100).toFixed(2)}%` : 'N/A';
const fmtNum = v => v != null ? Number(v).toFixed(4) : 'N/A';

const lines = [
  `📊 *Hola ${usuario.nombre}, tu resumen ${periodo}*`,
  `_${new Date().toLocaleString('es-ES')}_`,
  ''
];

for (const fondo of fondos) {
  if (fondo.error) {
    lines.push(`⚠️ *${fondo.ticker}*: ${fondo.observaciones}`);
    continue;
  }
  const rent = fondo.rentabilidad_acumulada;
  const emoji = rent != null && rent >= 0 ? '📈' : '📉';
  lines.push(`${emoji} *${fondo.ticker}*`);
  lines.push(`  Rentabilidad: ${fmtPct(rent)}`);
  lines.push(`  Sharpe: ${fmtNum(fondo.sharpe_ratio)}`);
  lines.push(`  Sortino: ${fmtNum(fondo.sortino_ratio)}`);
  lines.push(`  Max Drawdown: ${fmtPct(fondo.max_drawdown)}`);
  lines.push('');
}

const rankingS = metricas.ranking_sharpe || [];
const rankingR = metricas.ranking_rentabilidad || [];
if (rankingS.length > 0) {
  lines.push(`🏆 *Mejor Sharpe:* ${rankingS[0].ticker} (${fmtNum(rankingS[0].valor)})`);
}
if (rankingR.length > 0) {
  lines.push(`💰 *Mejor Rentabilidad:* ${rankingR[0].ticker} (${fmtPct(rankingR[0].valor)})`);
}

return [{ json: { mensaje: lines.join('\n'), chat_id: usuario.chat_id } }];
